css_custom_properties.block:
:root {
  --color-pink:        #FF4D8D;
  --color-purple:      #B14DFF;
  --color-violet:      #6366F1;
  --color-bg-darkest:  #0E1117;
  --color-bg-dark:     #1A1F2B;
  --color-bg-mid:      #2A2F3F;
  --color-text-muted:  #E5E7EB;
  --color-white:       #FFFFFF;
  --gradient-brand:    linear-gradient(135deg, #FF4D8D 0%, #B14DFF 50%, #9B6BFF 100%);
  --gradient-brand-h:  linear-gradient(90deg,  #FF4D8D 0%, #B14DFF 100%);
  --border-subtle:     rgba(255,255,255,0.08);
  --border-card:       rgba(255,255,255,0.06);
  --shadow-card:       0 2px 12px rgba(0,0,0,0.4);
  --shadow-popup:      0 8px 32px rgba(0,0,0,0.6);
  --shadow-glow:       0 4px 16px rgba(255,77,141,0.4);
  --radius-sm:         6px;
  --radius-md:         10px;
  --radius-lg:         14px;
  --radius-xl:         20px;
  --radius-pill:       999px;
  --font-sans:         'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --transition-fast:   120ms cubic-bezier(0.16,1,0.3,1);
  --transition-normal: 200ms cubic-bezier(0.16,1,0.3,1);
}
